   - 使用滚动数组优化空间复杂度。

### 代码实现

```cpp
/* 代码头注释：说明算法名称和关键技巧 */
// 算法名称：动态规划结合KMP算法
// 关键技巧：使用KMP算法预处理危险片段，动态规划计数不包含危险片段的DNA序列

#include <bits/stdc++.h>
using namespace std;
using ll = long long;
const int INF = 0x3f3f3f3f;
const int MOD = 1e9 + 7;

void computeLPSArray(const string& pattern, vector<int>& lps) {
    int len = 0;
    lps[0] = 0;
    int i = 1;
    while (i < pattern.size()) {
        if (pattern[i] == pattern[len]) {
            len++;
            lps[i] = len;
            i++;
        } else {
            if (len != 0) {
                len = lps[len - 1];
            } else {
                lps[i] = 0;
                i++;
            }
        }
    }
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n, k;
    cin >> n >> k;
    string S;
    cin >> S;

    vector<int> lps(k);
    computeLPSArray(S, lps);

    vector<vector<ll>> dp(n + 1, vector<ll>(k + 1, 0));
    dp[0][0] = 1;

    for (int i = 0; i < n; ++i) {
